import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"国子监与孔庙","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/guozijian.md","filePath":"landmarks/guozijian.md","lastUpdated":1784773307000}'),n={name:"landmarks/guozijian.md"};function o(d,t,i,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="国子监与孔庙" tabindex="-1">国子监与孔庙 <a class="header-anchor" href="#国子监与孔庙" aria-label="Permalink to &quot;国子监与孔庙&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-GTno1mONTfo?w=1200" alt="国子监与孔庙"></p><blockquote><p>&quot;千年学府，万世师表。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>国子监与孔庙位于北京市东城区国子监街，是中国元、明、清三代的最高学府和祭祀孔子的场所。孔庙是祭祀中国古代伟大思想家、教育家孔子的庙宇，国子监是中国古代最高教育行政机关和最高学府。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">8:30-16:30（淡季），8:30-17:00（旺季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">30元（孔庙和国子监联票）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1.5-2小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2/5号线雍和宫站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区国子监街15号（孔庙），国子监街13号（国子监）</td></tr></tbody></table><h2 id="孔庙" tabindex="-1">孔庙 <a class="header-anchor" href="#孔庙" aria-label="Permalink to &quot;孔庙&quot;">​</a></h2><h3 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h3><p>孔庙始建于元代大德六年（1302年），是元、明、清三代祭祀孔子的场所。孔庙的建筑规模仅次于山东曲阜孔庙，是全国第二大孔庙。</p><h4 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h4><p>孔庙的建筑沿中轴线对称分布，主要建筑有大成门、大成殿、崇圣祠等。</p><table tabindex="0"><thead><tr><th style="text-align:left;">建筑</th><th style="text-align:left;">功能</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>大成门</strong></td><td style="text-align:left;">孔庙正门</td><td style="text-align:left;">面阔五间，单檐歇山顶</td></tr><tr><td style="text-align:left;"><strong>大成殿</strong></td><td style="text-align:left;">主殿，祭祀孔子</td><td style="text-align:left;">面阔九间，重檐庑殿顶</td></tr><tr><td style="text-align:left;"><strong>崇圣祠</strong></td><td style="text-align:left;">祭祀孔子祖先</td><td style="text-align:left;">面阔五间，单檐歇山顶</td></tr><tr><td style="text-align:left;"><strong>碑亭</strong></td><td style="text-align:left;">存放御制碑</td><td style="text-align:left;">元代至清代御制碑</td></tr></tbody></table><h3 id="主要看点" tabindex="-1">主要看点 <a class="header-anchor" href="#主要看点" aria-label="Permalink to &quot;主要看点&quot;">​</a></h3><h4 id="大成殿" tabindex="-1">大成殿 <a class="header-anchor" href="#大成殿" aria-label="Permalink to &quot;大成殿&quot;">​</a></h4><p>大成殿是孔庙的主殿，殿内供奉着孔子的塑像。大成殿的建筑等级很高，仅次于故宫太和殿。</p><ul><li><strong>殿名由来</strong>：&quot;大成&quot;出自《孟子》，意为孔子集古圣先贤之大成</li><li><strong>建筑规模</strong>：面阔九间，进深五间</li><li><strong>屋顶形式</strong>：重檐殿顶，黄色琉璃瓦</li></ul><h4 id="碑林" tabindex="-1">碑林 <a class="header-anchor" href="#碑林" aria-label="Permalink to &quot;碑林&quot;">​</a></h4><p>孔庙内保存有大量历代御制碑和题名碑，是研究中国古代教育和科举制度的重要资料。</p><h2 id="国子监" tabindex="-1">国子监 <a class="header-anchor" href="#国子监" aria-label="Permalink to &quot;国子监&quot;">​</a></h2><h3 id="历史沿革-1" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革-1" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h3><p>国子监始建于元代大德十年（1306年），是中国古代最高教育行政机关和最高学府。国子监不仅培养了大批人才，也是中国古代教育制度的重要见证。</p><h4 id="建筑布局-1" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局-1" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h4><p>国子监的建筑沿中轴线分布，主要建筑有集贤门、太学门、辟雍殿、彝伦堂等。</p><table tabindex="0"><thead><tr><th style="text-align:left;">建筑</th><th style="text-align:left;">功能</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>集贤门</strong></td><td style="text-align:left;">国子监正门</td><td style="text-align:left;">面阔三间，单檐歇山顶</td></tr><tr><td style="text-align:left;"><strong>辟雍殿</strong></td><td style="text-align:left;">皇帝讲学之所</td><td style="text-align:left;">方形，重檐攒尖顶</td></tr><tr><td style="text-align:left;"><strong>彝伦堂</strong></td><td style="text-align:left;">国子监藏书之所</td><td style="text-align:left;">面阔七间，单檐歇山顶</td></tr><tr><td style="text-align:left;"><strong>敬一亭</strong></td><td style="text-align:left;">祭祀之所</td><td style="text-align:left;">六角形，重檐攒尖顶</td></tr></tbody></table><h3 id="主要看点-1" tabindex="-1">主要看点 <a class="header-anchor" href="#主要看点-1" aria-label="Permalink to &quot;主要看点&quot;">​</a></h3><h4 id="辟雍殿" tabindex="-1">辟雍殿 <a class="header-anchor" href="#辟雍殿" aria-label="Permalink to &quot;辟雍殿&quot;">​</a></h4><p>辟雍殿是国子监的核心建筑，是皇帝临雍讲学的场所。辟雍殿的建筑形式独特，是中国古代建筑中的精品。</p><ul><li><strong>建筑形式</strong>：方形，重檐攒尖顶</li><li><strong>屋顶形式</strong>：黄色琉璃瓦，四角攒尖</li><li><strong>内部陈设</strong>：皇帝宝座、讲经台等</li></ul><h4 id="十三经碑林" tabindex="-1">十三经碑林 <a class="header-anchor" href="#十三经碑林" aria-label="Permalink to &quot;十三经碑林&quot;">​</a></h4><p>国子监内保存有清代镌刻的《十三经》石碑，共189块，是中国现存最完整的石刻经书。</p><ul><li><strong>刻经时间</strong>：清代雍正年间</li><li><strong>石碑数量</strong>：189块</li><li><strong>内容</strong>：《周易》《尚书》《诗经》等十三部儒家经典</li></ul><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><h3 id="儒家文化的传承" tabindex="-1">儒家文化的传承 <a class="header-anchor" href="#儒家文化的传承" aria-label="Permalink to &quot;儒家文化的传承&quot;">​</a></h3><p>孔庙和国子监是中国儒家文化的重要载体，见证了中国古代教育制度的发展和演变。</p><h3 id="科举制度的见证" tabindex="-1">科举制度的见证 <a class="header-anchor" href="#科举制度的见证" aria-label="Permalink to &quot;科举制度的见证&quot;">​</a></h3><p>国子监是中国古代科举制度的重要见证，培养了大量的人才，对中国古代政治、文化产生了深远的影响。</p><h3 id="建筑艺术的精品" tabindex="-1">建筑艺术的精品 <a class="header-anchor" href="#建筑艺术的精品" aria-label="Permalink to &quot;建筑艺术的精品&quot;">​</a></h3><p>孔庙和国子监的建筑体现了中国古代建筑的精华，是研究中国古代建筑艺术的重要实物资料。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约1.5小时）</strong>：</p><p>孔庙：先师门 → 大成门 → 大成殿 → 崇圣祠 → 碑亭 国子监：集贤门 → 太学门 → 辟雍殿 → 彝伦堂 → 敬一亭</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>最佳时间</strong>：工作日人较少，适合慢慢参观</li><li><strong>讲解服务</strong>：建议租用讲解器或请导游，了解更多历史知识</li><li><strong>拍照位置</strong>：大成殿前、辟雍殿前都是绝佳拍照点</li><li><strong>周边游览</strong>：参观完后可以到雍和宫、五道营胡同游览</li><li><strong>文化体验</strong>：可以带孩子来此感受传统文化氛围</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">2/5号线雍和宫站F口，步行约5分钟</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">13、84、116、117、684路雍和宫站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;孔庙和国子监博物馆&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">雍和宫</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">藏传佛教寺院</td></tr><tr><td style="text-align:left;">五道营胡同</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">文艺胡同</td></tr><tr><td style="text-align:left;">地坛公园</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">皇家祭祀场所</td></tr><tr><td style="text-align:left;">街</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">美食街</td></tr></tbody></table><hr><p><strong>📍 地址</strong>：北京市东城区国子监街15号（孔庙），国子监街13号（国子监） <strong>🚇 地铁</strong>：2/5号线雍和宫站F口 <strong>📞 电话</strong>：010-84027224 <strong>🌐 官网</strong>：<a href="http://www.kmgzj.com" target="_blank" rel="noreferrer">www.kmgzj.com</a></p><p><strong>💡 Tips</strong>：国子监街上有许多老字号店铺，参观完后可以顺便逛逛，感受老北京的风情。</p>',52)])])}const y=e(n,[["render",o]]);export{f as __pageData,y as default};
